class Solution {
    public int findIntegers(int n) {
        int[] fib = new int[31];
        fib[0] = 1;
        fib[1] = 2;
        for (int i = 2; i <= 30; i++) {
            fib[i] = fib[i - 1] + fib[i - 2];
        }
        int sum = 0;
        boolean prev = false;
        for (int i = 30; i >= 0; i--) {
            if ((n & (1 << i)) != 0) {
                sum += fib[i];
                if (prev) {
                    sum--;
                    break;
                }
                prev = true;
            } else {
                prev = false;
            }
        }
        return sum + 1;
    }
}
